+func TestHeadroomGuard_ComputeEffectiveLimit(t *testing.T) {
+	cfg := DefaultHeadroomConfig()
+	guard := NewHeadroomGuard(cfg)
+	defer guard.Stop()
+
+	tests := []struct {
+		name           string
+		limits         *ResourceLimits
+		expectedLimit  int
